##### 1.4 WebSocket 实时通信 (Day 8)

**WebSocket 服务** (`src/services/socket.ts`):
```typescript
import { io, Socket } from 'socket.io-client';

export class DashboardSocket {
  private socket: Socket;
  private store: any;

  constructor(url: string, store: any) {
    this.socket = io(url);
    this.store = store;
    this.setupListeners();
  }

  private setupListeners() {
    // 订阅项目事件
    this.socket.emit('subscribe', { projectId: 'default' });

    // 迭代状态变更
    this.socket.on('iteration.status_changed', (data) => {
      this.store.iteration.updateIteration(data);
    });

    // Agent 进度更新
    this.socket.on('agent.progress', (data) => {
      this.store.agent.updateAgent(data);
    });

    // 实时日志
    this.socket.on('log.line', (data) => {
      this.store.system.addLog(data);
    });

    // 系统指标
    this.socket.on('system.metrics', (data) => {
      this.store.system.updateMetrics(data);
    });
  }

  public disconnect() {
    this.socket.disconnect();
  }
}
```

