### 📊 **P1 - 高优先级** (预计 5-7 天)

#### 性能优化方案

**1. BaseAgent 增强**
```typescript
export abstract class BaseAgent {
  // 新增超时控制
  async executeWithTimeout(
    prompt: string,
    timeout: number = 300000
  ): AsyncGenerator<any> {
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), timeout);

    try {
      const stream = this.agent.iterate(prompt, {
        signal: controller.signal
      });

      for await (const event of stream) {
        yield event;
      }
    } finally {
      clearTimeout(timeoutId);
    }
  }

  // 新增重试机制
  async executeWithRetry(
    prompt: string,
    maxRetries: number = 3
  ): Promise<string> {
    let lastError: Error;

    for (let i = 0; i < maxRetries; i++) {
      try {
        return await this.executeAndCollect(prompt);
      } catch (error) {
        lastError = error;
        await this.sleep(Math.pow(2, i) * 1000); // 指数退避
      }
    }

    throw lastError;
  }

  // 性能监控
  private metrics = {
    executionTimes: [] as number[],
    apiCalls: 0,
    errors: 0
  };

  getMetrics() {
    return {
      avgExecutionTime: average(this.metrics.executionTimes),
      totalApiCalls: this.metrics.apiCalls,
      errorRate: this.metrics.errors / this.metrics.apiCalls
    };
  }
}
```

**2. 缓存机制**
```typescript
export class CacheManager {
  private cache = new Map<string, { value: any; expires: number }>();

  async get<T>(key: string): Promise<T | null> {
    const item = this.cache.get(key);

    if (!item) return null;

    if (Date.now() > item.expires) {
      this.cache.delete(key);
      return null;
    }

    return item.value;
  }

  async set(key: string, value: any, ttl: number = 3600000) {
    this.cache.set(key, {
      value,
      expires: Date.now() + ttl
    });
  }

  // 缓存代码分析结果
  async cacheCodeAnalysis(projectPath: string, analysis: any) {
    await this.set(`code:${projectPath}`, analysis, 3600000); // 1小时
  }
}
```

